113	fn compile_c_file(path: &str, output: &str) {
114	    let status = Command::new("gcc")
115	        .arg(path)
116	        .arg("-o")
117	        .arg(output)
118	        .arg("-lm")
119	        .status()
120	        .expect("failed to compile C code");
121	
122	    if !status.success() {
123	        panic!("C compilation failed");
124	    }
125	}
