383	pub fn report(line: usize, column: usize, message: &str, place: &str, file: Option<&str>) {
384	    let (filename, source) = get_source_and_file().unwrap_or_default();
385	
386	    let mut err = ERROR.lock().unwrap();
387	
388	    // --- Header ---
389	    let span = Span { line, column };
390	    let err_kind = classify_error(&span, place, message);
391	    if let Some(f) = file {
392	        println!(
393	            "\n{BOLD}{RED}{err_kind}{RESET} {DIM}({place}){RESET} in {DIM}{f}{RESET}{BOLD}: {message}{RESET}"
394	        );
395	    } else {
396	        println!(
397	            "\n{BOLD}{RED}{err_kind}{RESET} {DIM}({place}){RESET}{BOLD}: {message}{RESET}"
398	        );
399	    }
400	
401	    // --- Location ---
402	    println!("{DIM}  at {BRIGHT_CYAN}line {line}{RESET}{DIM}, column {column}{RESET}\n");
403	
404	    // --- Source context ---
405	    if !source.is_empty() && line > 0 {
406	        let prefix = "    | ";
407	        let line_width = format!("{:>3}", line).len();
408	
409	        if line as isize - 3 > 0 {
410	            println!("{BRIGHT_CYAN}{:>3}{RESET}{DIM} | {RESET}{}", line - 3, get_line(line - 3, &source));
411	        }
412	
413	        if line as isize - 2 > 0 {
414	            println!("{BRIGHT_CYAN}{:>3}{RESET}{DIM} | {RESET}{}", line - 2, get_line(line - 2, &source));
415	        }
416	
417	        if line as isize - 1 > 0 {
418	            println!("{BRIGHT_CYAN}{:>3}{RESET}{DIM} | {RESET}{}", line - 1, get_line(line - 1, &source));
419	        }
420	
421	        println!("{BRIGHT_CYAN}{:>3}{RESET}{BRIGHT_RED} | {RESET}{}{BG_RED}{RESET}", line, get_line(line, &source));
422	
423	        let prefix_len = prefix.len();
424	        let indent = (prefix_len + column).saturating_sub(line_width + 3);
425	        let padding = " ".repeat(indent);
426	        println!("{prefix}{padding}{BRIGHT_RED}^{RESET} {DIM}{message}{RESET}");
427	    }
428	
429	    // --- Stack trace ---
430	    let stack = CALL_STACK.lock().unwrap();
431	    if !stack.is_empty() {
432	        println!("\n{BRIGHT_MAGENTA}Call stack:{RESET}");
433	        for func in stack.iter().rev() {
434	            println!("  {BRIGHT_CYAN}--> {RESET}{BRIGHT_YELLOW}{func}{RESET}");
435	        }
436	    }
437	
438	    println!("{RESET}\n");
439	
440	    *err = Err(ObstructError::new(line, column, message, Some(filename)));
441	}
