443	pub fn parse(source: String) -> Expr {
444	    let mut scanner = Scanner::new(source);
445	    let tokens = scanner.scan_tokens();
446	    let mut parser = Parser::new(tokens);
447	    let expr = parser.parse();
448	
449	    expr
450	}
