7	pub struct Scanner {
8	    source: String,
9	    tokens: Vec<Token>,
10	    start: usize,
11	    current: usize,
12	    line: usize,
13	    column: usize,
14	    keywords: HashMap<String, TokenType>,
15	    prev_c: char,
16	}
17	
18	impl Scanner {
19	    pub fn new(source: String) -> Self {
20	        let mut keywords = HashMap::new();
21	
22	        keywords.insert("cls".into(), TokenType::Cls);
23	        keywords.insert("ret".into(), TokenType::Ret);
24	        keywords.insert("comp".into(), TokenType::Comp);
25	        keywords.insert("stc".into(), TokenType::Stc);
26	        keywords.insert("ovr".into(), TokenType::Ovr);
27	        keywords.insert("err".into(), TokenType::Err);
28	        keywords.insert("del".into(), TokenType::Del);
29	        keywords.insert("use".into(), TokenType::Use);
30	        keywords.insert("for".into(), TokenType::For);
31	        keywords.insert("fn".into(), TokenType::Fn);
32	        keywords.insert("mac".into(), TokenType::Mac);
33	        keywords.insert("lam".into(), TokenType::Lam);
34	        keywords.insert("std".into(), TokenType::Std);
35	
36	        Scanner {
37	            source,
38	            tokens: Vec::new(),
39	            start: 0,
40	            current: 0,
41	            line: 1,
42	            column: 1,
43	            keywords,
44	            prev_c: '\0',
45	        }
46	    }
47	
48	    pub fn scan_tokens(&mut self) -> &Vec<Token> {
49	        while !self.is_at_end() {
50	            self.start = self.current;
51	            self.scan_token();
52	        }
53	
54	        self.tokens.push(Token::new(
55	            TokenType::EOF,
56	            String::new(),
57	            String::new(),
58	            self.line,
59	            self.column,
60	        ));
61	        &self.tokens
62	    }
63	
64	    fn is_at_end(&self) -> bool {
65	        self.current >= self.source.len()
66	    }
67	
68	    fn scan_token(&mut self) {
69	        let c = self.advance();
70	        match c {
71	            '(' => self.add_token(TokenType::LeftParen),
72	            ')' => self.add_token(TokenType::RightParen),
73	            '{' => self.add_token(TokenType::LeftBrace),
74	            '}' => self.add_token(TokenType::RightBrace),
75	            '[' => self.add_token(TokenType::LeftBrack),
76	            ']' => self.add_token(TokenType::RightBrack),
77	            '&' => self.add_token(TokenType::And),
78	            '|' => self.add_token(TokenType::Or),
79	            ',' => self.add_token(TokenType::Comma),
80	            '.' => self.add_token(TokenType::Dot),
81	            '%' => self.add_token(TokenType::Mod),
82	            '-' => {
83	                if self.match_char('>') {
84	                    self.add_token(TokenType::MinusRight);
85	                } else {
86	                    self.add_token(TokenType::Minus);
87	                }
88	            }
89	            '+' => self.add_token(TokenType::Plus),
90	            ';' => self.add_token(TokenType::Semicolon),
91	            ':' => {
92	                if self.match_char(':') {
93	                    self.add_token(TokenType::DoubleColon);
94	                } else {
95	                    self.add_token(TokenType::Colon);
96	                }
97	            }
98	            '*' => {
99	                if self.match_char('*') {
100	                    self.add_token(TokenType::StarStar);
101	                } else {
102	                    self.add_token(TokenType::Star);
103	                }
104	            }
105	            '~' => {
106	                if self.match_char('?') {
107	                    self.add_token(TokenType::TildeQuestionMark);
108	                } else {
109	                    self.add_token(TokenType::Tilde);
110	                }
111	            }
112	            '?' => self.add_token(TokenType::QuestionMark),
113	            '$' => {
114	                if self.match_char('?') {
115	                    self.add_token(TokenType::DollarQuestionMark);
116	                } else {
117	                    self.add_token(TokenType::Dollar);
118	                }
119	            }
120	            '^' => {
121	                if self.match_char('^') {
122	                    self.add_token(TokenType::DoubleUpArrow);
123	                } else {
124	                    self.add_token(TokenType::UpArrow);
125	                }
126	            }
127	            '!' => {
128	                if self.match_char('=') {
129	                    self.add_token(TokenType::BangEqual);
130	                } else {
131	                    self.add_token(TokenType::Bang);
132	                }
133	            }
134	            '=' => {
135	                if self.match_char('=') {
136	                    self.add_token(TokenType::EqualEqual);
137	                } else {
138	                    self.add_token(TokenType::Equal);
139	                }
140	            }
141	            '<' => {
142	                if self.match_char('=') {
143	                    self.add_token(TokenType::LessEqual);
144	                } else if self.match_char('<') {
145	                    self.add_token(TokenType::LessLess);
146	                } else {
147	                    self.add_token(TokenType::Less);
148	                }
149	            }
150	            '>' => {
151	                if self.match_char('=') {
152	                    self.add_token(TokenType::GreaterEqual);
153	                } else if self.match_char('>') {
154	                    self.add_token(TokenType::GreaterGreater);
155	                } else {
156	                    self.add_token(TokenType::Greater);
157	                }
158	            }
159	            '#' => {
160	                self.add_token(TokenType::Hash);
161	            }
162	            '@' => self.add_token(TokenType::At),
163	            '£' => self.add_token(TokenType::Pound),
164	            '¬' => self.add_token(TokenType::NotSign),
165	            '/' => {
166	                if self.match_char('/') {
167	                    // Single-line comment
168	                    while self.peek() != '\n' && !self.is_at_end() {
169	                        self.advance();
170	                    }
171	                } else if self.match_char('*') {
172	                    // Multi-line comment
173	                    self.block_comment();
174	                } else {
175	                    self.add_token(TokenType::Slash);
176	                }
177	            }
178	            '\\' => self.add_token(TokenType::BackSlash),
179	            ' ' | '\r' | '\t' | '\n' => {}
180	            '`' => self.backtick(),
181	            '"' => self.string(),
182	            '\'' => self.character(),
183	            _ => {
184	                if c.is_ascii_digit() {
185	                    self.number();
186	                } else if self.alpha(c) {
187	                    self.identifier();
188	                } else {
189	                    error(
190	                        Span {
191	                            line: self.line,
192	                            column: self.column,
193	                        },
194	                        "Unexpected character.",
195	                        "scanning",
196	                    );
197	                }
198	            }
199	        }
200	    }
201	
202	    fn advance(&mut self) -> char {
203	        let c = self.source[self.current..].chars().next().unwrap();
204	        self.current += c.len_utf8();
205	
206	        if c == '\n' {
207	            self.line += 1;
208	            self.column = 1;
209	        } else {
210	            self.column += 1;
211	        }
212	
213	        c
214	    }
215	
216	    fn add_token(&mut self, token_type: TokenType) {
217	        self.add_token_literal(token_type, "".into());
218	    }
219	
220	    fn add_token_literal(&mut self, token_type: TokenType, literal: String) {
221	        let text = self.source[self.start..self.current].to_string();
222	
223	        let token_column = self.column - text.chars().count();
224	
225	        self.tokens.push(Token::new(
226	            token_type,
227	            text,
228	            literal,
229	            self.line,
230	            token_column.max(1),
231	        ));
232	    }
233	
234	    fn match_char(&mut self, expected: char) -> bool {
235	        if self.is_at_end() {
236	            return false;
237	        }
238	
239	        if self.peek() != expected {
240	            return false;
241	        }
242	
243	        self.advance();
244	        true
245	    }
246	
247	    fn peek(&self) -> char {
248	        if self.is_at_end() {
249	            '\0'
250	        } else {
251	            self.source[self.current..].chars().next().unwrap()
252	        }
253	    }
254	
255	    fn peek_next(&self) -> char {
256	        let mut chars = self.source[self.current..].chars();
257	        chars.next();
258	        chars.next().unwrap_or('\0')
259	    }
260	
261	    fn alpha(&mut self, c: char) -> bool {
262	        let output =
263	            (c.is_ascii_alphabetic() || c == '_' || c == '¬') && !(c == '_' && self.prev_c == '_');
264	        self.prev_c = c;
265	        output
266	    }
267	
268	    fn alpha_numeric(&mut self, c: char) -> bool {
269	        self.alpha(c) || c.is_ascii_digit()
270	    }
271	
272	    fn string(&mut self) {
273	        let mut value = String::new();
274	
275	        while !self.is_at_end() {
276	            let c = self.advance();
277	
278	            match c {
279	                '"' => {
280	                    // End of string
281	                    self.add_token_literal(TokenType::String, value);
282	                    return;
283	                }
284	                '\\' => {
285	                    if self.is_at_end() {
286	                        error(
287	                            Span {
288	                                line: self.line,
289	                                column: self.column,
290	                            },
291	                            "Unterminated escape sequence in string.",
292	                            "lexing",
293	                        );
294	                        return;
295	                    }
296	
297	                    let esc = self.advance();
298	                    match esc {
299	                        'n' => value.push('\n'),
300	                        't' => value.push('\t'),
301	                        'r' => value.push('\r'),
302	                        '\\' => value.push('\\'),
303	                        'x' => value.push_str("\\x"),
304	                        '0' => value.push_str("\0"),
305	                        '"' => value.push('"'),
306	                        _ => {
307	                            error(
308	                                Span {
309	                                    line: self.line,
310	                                    column: self.column,
311	                                },
312	                                &format!("Invalid escape sequence: \\{}", esc),
313	                                "lexing",
314	                            );
315	                            return;
316	                        }
317	                    }
318	                }
319	                _ => value.push(c),
320	            }
321	        }
322	
323	        error(
324	            Span {
325	                line: self.line,
326	                column: self.column,
327	            },
328	            "Unterminated string literal.",
329	            "lexing",
330	        );
331	    }
332	
333	    fn number(&mut self) {
334	        while self.peek().is_ascii_digit() {
335	            self.advance();
336	        }
337	
338	        // Look for fractional part
339	        if self.peek() == '.' && self.peek_next().is_ascii_digit() {
340	            self.advance(); // consume '.'
341	            while self.peek().is_ascii_digit() {
342	                self.advance();
343	            }
344	            let value = self.source[self.start..self.current].to_string();
345	            self.add_token_literal(TokenType::Float, value);
346	        } else {
347	            let value = self.source[self.start..self.current].to_string();
348	            self.add_token_literal(TokenType::Int, value);
349	        }
350	    }
351	
352	    fn identifier(&mut self) {
353	        while self.alpha_numeric(self.peek()) {
354	            self.advance();
355	        }
356	
357	        // Handle '::' type sequences like 'str::i32'
358	        while self.peek() == ':' && self.peek_next() == ':' {
359	            self.advance(); // consume first ':'
360	            self.advance(); // consume second ':'
361	
362	            // continue scanning the next identifier part
363	            while self.alpha_numeric(self.peek()) {
364	                self.advance();
365	            }
366	        }
367	
368	        let text = self.source[self.start..self.current].to_string();
369	        if let Some(token_type) = self.keywords.get(&text) {
370	            self.add_token(*token_type);
371	        } else {
372	            self.add_token(TokenType::Ident);
373	        }
374	    }
375	
376	    fn character(&mut self) {
377	        if self.is_at_end() {
378	            error(
379	                Span {
380	                    line: self.line,
381	                    column: self.column,
382	                },
383	                "Unterminated character literal.",
384	                "lexing",
385	            );
386	            return;
387	        }
388	
389	        let c = self.advance();
390	        let value = if c == '\\' {
391	            if self.is_at_end() {
392	                error(
393	                    Span {
394	                        line: self.line,
395	                        column: self.column,
396	                    },
397	                    "Unterminated escape sequence.",
398	                    "lexing",
399	                );
400	                return;
401	            }
402	            let esc = self.advance();
403	            match esc {
404	                'n' => "\n".to_string(),
405	                't' => "\t".to_string(),
406	                '\\' => "\\".to_string(),
407	                '\'' => "'".to_string(),
408	                'r' => "\r".to_string(),
409	                '0' => "\0".to_string(),
410	                _ => {
411	                    error(
412	                        Span {
413	                            line: self.line,
414	                            column: self.column,
415	                        },
416	                        &format!("Invalid escape sequence: \\{}", esc),
417	                        "lexing",
418	                    );
419	                    return;
420	                }
421	            }
422	        } else {
423	            c.to_string()
424	        };
425	
426	        if self.peek() != '\'' {
427	            error(
428	                Span {
429	                    line: self.line,
430	                    column: self.column,
431	                },
432	                "Character literal too long or missing closing quote.",
433	                "lexing",
434	            );
435	            return;
436	        }
437	
438	        self.advance(); // Consume closing quote
439	        self.add_token_literal(TokenType::Char, value);
440	    }
441	
442	    fn backtick(&mut self) {
443	        if self.is_at_end() {
444	            error(
445	                Span {
446	                    line: self.line,
447	                    column: self.column,
448	                },
449	                "Expected character after backtick (`)",
450	                "lexing",
451	            );
452	            return;
453	        }
454	
455	        let c = self.advance();
456	        match c {
457	            'f' => self.add_token(TokenType::False),
458	            't' => self.add_token(TokenType::True),
459	            's' => self.tokens.push(Token::new(
460	                TokenType::String,
461	                String::new(),
462	                String::new(),
463	                self.line,
464	                self.column,
465	            )),
466	            'v' => self.add_token(TokenType::This),
467	            _ => {
468	                error(
469	                    Span {
470	                        line: self.line,
471	                        column: self.column,
472	                    },
473	                    "Invalid character after backtick (`)",
474	                    "lexing",
475	                );
476	                return;
477	            }
478	        }
479	
480	        if self.alpha(self.peek()) {
481	            error(
482	                Span {
483	                    line: self.line,
484	                    column: self.column,
485	                },
486	                "Only a single character should be after a backtick (`)",
487	                "lexing",
488	            );
489	        }
490	    }
491	
492	    fn block_comment(&mut self) {
493	        while !self.is_at_end() {
494	            if self.peek() == '*' {
495	                self.advance();
496	                if self.peek() == '/' {
497	                    self.advance();
498	                    return;
499	                }
500	            } else {
501	                self.advance();
502	            }
503	        }
504	
505	        error(
506	            Span {
507	                line: self.line,
508	                column: self.column,
509	            },
510	            "Unterminated block comment.",
511	            "lexing",
512	        );
513	    }
514	}
