484	                        ctx.body.push('.');
485	
486	                        ctx.body
487	                            .push_str(&cte.c_member_name(&var_type, member, *span));
488	
489	                        ctx.body.push('=');
490	                        right.to_c(cte, ctx);
491	                    }
492	                    _ => {
493	                        error(*span, "Invalid assignment target", "transpiler");
494	                    }
495	                }
496	                true
497	            }
498	
499	            Expr::Return(expr, _span) => {
500	                ctx.body.push_str("return ");
501	                expr.to_c(cte, ctx);
502	                true
503	            }
504	
505	            Expr::Delete(name) => {
506	                cte.del_var(name);
507	                false
508	            }
509	
510	            Expr::Nothing() => false,
511	
512	            Expr::While(cond, block) => {
513	                ctx.body.push_str("while (");
514	                cond.to_c(cte, ctx);
515	                ctx.body.push_str("){\n");
516	                block.to_c(cte, ctx);
517	                ctx.body.push_str("}");
518	                false
519	            }
520	
521	            Expr::Use { .. } => false,
522	
523	            Expr::Class(ty, members, span) => {
524	                let c_type_name = cte.c_type_name(ty, ctx, *span);
525	                ctx.types.push_str("struct ");
526	                ctx.types.push_str(&c_type_name);
527	                ctx.types.push_str(" {\n");
528	                let member_lines: Vec<String> = members
529	                    .iter()
530	                    .map(|(name, member_type)| {
531	                        let ty_name = cte.c_type_name(member_type, ctx, *span);
532	                        let m_name = cte.c_member_name(ty, name, *span);
533	                        format!("{} {}", ty_name, m_name)
534	                    })
535	                    .collect();
536	                ctx.types.push_str(&member_lines.join(";\n"));
537	                ctx.types.push_str(";\n");
538	                if ctx.types.ends_with("; \n") {
539	                    ctx.types.pop();
540	                    ctx.types.pop();
541	                    ctx.types.push('\n');
542	                }
543	                ctx.types.push_str("};\n");
544	
545	                true
546	            }
547	
548	            Expr::Member(expr, member, span) => {
549	                let var_type = expr.get_type(cte);
550	                expr.to_c(cte, ctx);
551	
552	                ctx.body.push('.');
553	
554	                ctx.body
555	                    .push_str(&cte.c_member_name(&var_type, member, *span));
556	                false
557	            }
558	
559	            Expr::Ref(expr, _span) => {
560	                ctx.body.push('&');
561	                expr.to_c(cte, ctx);
562	                false
563	            }
564	            Expr::Deref(expr, _span) => {
565	                ctx.body.push_str("(*");
566	                expr.to_c(cte, ctx);
567	                ctx.body.push(')');
568	                false
569	            }
570	
571	            Expr::Nth(left, right, _span) => {
572	                left.to_c(cte, ctx);
573	
574	                ctx.body.push('[');
575	                right.to_c(cte, ctx);
576	                ctx.body.push(']');
577	
578	                false
579	            }
580	
581	            _ => panic!("unexpected expression (for transpilation) '{:?}'", self),
582	        }
583	    }
584	
585	    pub fn pre_transpile(
586	        &self,
587	        cte: &mut CompileTimeEnv,
588	        ctx: &mut CodeGenContext,
589	        programs_to_transpile: &mut HashMap<String, bool>,
590	        current_file_dir: &str,
591	    ) {
592	        match self {
593	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
594	                if cte.get_var(name).is_some() {
595	                    error(
596	                    *span,
597	                    format!(
598	                        "Variable '{}' already exists and is immutable, could not declare function",
599	                        name
600	                    )
601	                        .as_str(),"pre-transpiling"
602	                );
603	                }
604	                let mut arg_types = vec![];
605	                for arg in args {
606	                    arg_types.push(arg.1.clone());
607	                }
608	
609	                // Push scope and declare parameters.
610	                cte.push_scope();
611	                for arg in args {
612	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
613	                }
614	
615	                // Process the body first so local variable declarations (like #x = ...)
616	                // are registered in the scope. This makes them visible to returned_type()
617	                // and get_type() calls that resolve variable names.
618	                block.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
619	
620	                let ret_type = block.returned_type(cte, *span);
621	                let return_type = if return_type.is_some() {
622	                    return_type.clone().unwrap()
623	                } else {
624	                    if let Some(ty) = ret_type.clone() {
625	                        ty
626	                    } else {
627	                        nil_type()
628	                    }
629	                };
630	
631	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
632	                // Declare the variable first so c_func_instance_name can find it
633	                cte.declare_global_var(
634	                    name.clone(),
635	                    false,
636	                    Type::with_generics("func", {
637	                        arg_types.push(return_type.clone());
638	                        let output = arg_types;
639	                        output
640	                    }),
641	                );
642	
643	                let return_type_name = cte.c_type_name(&return_type, ctx, *span);
644	                let func_name = cte.c_func_instance_name(&name, &[], *span);
645	
646	                let mut decl_params: Vec<String> = Vec::new();
647	                for arg in args {
648	                    let param = cte.c_param_type(&arg.1, ctx, *span);
649	                    let var = cte.c_var_name(&arg.0, *span);
650	                    decl_params.push(format!("{} {}", param, var));
651	                }
652	                ctx.declarations
653	                    .push_str(&format!("{} {}(", return_type_name, func_name));
654	                ctx.declarations.push_str(&decl_params.join(", "));
655	                ctx.declarations.push_str(");\n");
656	
657	                cte.pop_scope();
658	            }
659	            Expr::Use { kind, path, span } => {
660	                let full_path = match kind {
661	                    UseKind::Std => format!("{}{}", STD_PATH, path),
662	                    UseKind::Normal => {
663	                        if current_file_dir.is_empty() {
664	                            path.to_string()
665	                        } else {
666	                            format!("{}/{}", current_file_dir, path)
667	                        }
668	                    }
669	                };
670	
671	                if !Path::new(&full_path).exists() {
672	                    error(*span, &format!("File at path '{}' does not exist!", full_path), "pre-transpiling");
673	                    return;
674	                }
675	
676	                if !programs_to_transpile.contains_key(&full_path) {
677	                    programs_to_transpile.insert(full_path.clone(), true);
678	                    // Process this file immediately so its functions are available to subsequent
679	                    // declarations in the current file
680	                    let source = std::fs::read_to_string(&full_path)
681	                        .unwrap_or_else(|_| panic!("Failed to read {}", full_path));
682	                    let imported_ast = {
683	                        let mut scanner = crate::scanner::Scanner::new(source.clone());
684	                        let tokens = scanner.scan_tokens();
685	                        let mut parser = crate::parser::Parser::new(tokens);
686	                        parser.parse()
687	                    };
688	                    let imported_dir = std::path::Path::new(&full_path)
689	                        .parent()
690	                        .map(|p| p.to_string_lossy().to_string())
691	                        .unwrap_or_default();
692	                    imported_ast.pre_transpile(cte, ctx, programs_to_transpile, &imported_dir);
693	                }
694	            }
695	
696	            Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
697	                for expr in exprs {
698	                    expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
699	                }
700	            }
701	
702	            Expr::Discard(expr) => {
703	                expr.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir)
704	            }
705	
706	            Expr::Class(ty, members, span) => {
707	                cte.register_class(ty.clone());
708	
709	                for member in members {
710	                    cte.declare_member(member.0.clone(), member.1.clone(), ty.clone());
711	                }
712	
713	                let c_type_name = cte.c_type_name(ty, ctx, *span);
714	                ctx.include.push_str("struct ");
715	                ctx.include.push_str(&c_type_name);
716	                ctx.include.push_str(";\n");
717	
718	                ctx.types.push_str("\ntypedef struct ");
719	                ctx.types.push_str(&c_type_name);
720	                ctx.types.push(' ');
721	                ctx.types.push_str(&c_type_name);
722	                ctx.types.push_str(";\n");
723	            }
724	
725	            Expr::Declare(name, var_type, expr, is_mutable, _span) => {
726	                if let Some(var_type) = var_type {
727	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone());
728	                } else if let Some(expr_box) = expr {
729	                    let t = expr_box.get_type(cte);
730	                    cte.declare_var(name.clone(), *is_mutable, t);
731	                }
732	                if let Some(expr_box) = expr {
733	                    expr_box.pre_transpile(cte, ctx, programs_to_transpile, current_file_dir);
734	                }
735	            }
736	
737	            _ => {}
738	        }
739	    }
740	
741	    fn get_type(&self, cte: &mut CompileTimeEnv) -> Type {
742	        match self {
743	            Expr::Int(_) => "i32".into(),
744	            Expr::Float(_) => "f64".into(),
745	            Expr::Str(_) => "strlit".into(),
746	            Expr::Bool(_)
747	            | Expr::EqualEqual(..)
748	            | Expr::BangEqual(..)
749	            | Expr::Less(..)
750	            | Expr::LessEqual(..)
751	            | Expr::Greater(..)
752	            | Expr::GreaterEqual(..) => "bool".into(),
753	            Expr::Char(_) => "char".into(),
754	            Expr::Add(l, _, _)
755	            | Expr::Sub(l, ..)
756	            | Expr::Mult(l, ..)
757	            | Expr::Power(l, ..)
758	            | Expr::Div(l, ..) => l.get_type(cte),
759	            Expr::Return(_, _span) => nil_type(),
760	            Expr::Nth(..) => "char".into(),
761	            Expr::CallFunc(name, _, _, span) => {
762	                let function = cte
763	                    .get_var(name)
764	                    .unwrap_or_else(|| {
765	                        error(
766	                            *span,
767	                            &format!("Function not defined: {}", name),
768	                            "type checker",
769	                        );
770	                        (false, nil_type())
771	                    })
772	                    .1;
773	                function.generics().last().cloned().unwrap_or_else(nil_type)
774	            }
775	            Expr::StmtBlock(exprs, _span) => exprs.last().unwrap().get_type(cte),
776	            Expr::StmtBlockWithScope(exprs, _span) => exprs.last().unwrap().get_type(cte),
777	            Expr::Variable(name, span) => {
778	                cte.get_var(name)
779	                    .unwrap_or_else(|| {
780	                        error(
781	                            *span,
782	                            &format!("Variable not defined: {}", name),
783	                            "type checker",
784	                        );
785	                        (false, nil_type())
786	                    })
787	                    .1
788	            }
789	            Expr::Discard(..) => nil_type(),
790	            Expr::Print(expr, _) => expr.get_type(cte),
791	            Expr::If(_, block, ..) => block.get_type(cte),
792	            Expr::Member(expr, member_name, span) => {
793	                let var_type = expr.get_type(cte);
794	
795	                let member = cte.get_member_type(&var_type, member_name);
796	
797	                let member_type = if member.is_none() {
798	                    error(
799	                        *span,
800	                        &format!(
801	                            "Member '{}' not defined for type '{}'",
802	                            member_name, var_type
803	                        ),
804	                        "type checker",
805	                    );
806	                    nil_type()
807	                } else {
808	                    member.unwrap()
809	                };
810	
811	                member_type
812	            }
813	
814	            Expr::Ref(expr, _span) => {
815	                let expr_type = expr.get_type(cte);
816	                cte.register_type(expr_type.clone());
817	                Type::with_generics("ref", vec![expr_type])
818	            }
819	            Expr::Deref(expr, span) => {
820	                let expr_type = expr.get_type(cte);
821	                if expr_type.name() != "ref" {
822	                    error(*span, "Could not deref non-reference", "type checker");
823	                    return nil_type();
824	                }
825	                expr_type.generics()[0].clone()
826	            }
827	            _ => panic!("unexpected expression (for type check) '{:?}'", self),
828	        }
829	    }
830	
831	    fn returned_type(&self, cte: &mut CompileTimeEnv, span: Span) -> Option<Type> {
832	        match self {
833	            Expr::Return(expr, _span) => Some(expr.get_type(cte)),
834	            Expr::Discard(expr) => expr.returned_type(cte, span),
835	            Expr::StmtBlock(exprs, span) => {
836	                let mut return_type = None;
837	                for expr in exprs {
838	                    let ret_type = expr.returned_type(cte, *span);
839	                    if let Some(returned_type) = ret_type {
840	                        if let Some(expected_type) = return_type.clone() {
841	                            if expected_type != returned_type {
842	                                error(
843	                                    {
844	                                        let expr_span = expr.get_span();
845	                                        if expr_span == Span::empty() {
846	                                            *span
847	                                        } else {
848	                                            expr_span
849	                                        }
850	                                    },
851	                                    "Returned type was different to previous returned type",
852	                                    "returned type checker",
853	                                );
854	                            }
855	                        } else {
856	                            return_type = Some(returned_type);
857	                        }
858	                    }
859	                }
860	                return_type
861	            }
862	            Expr::StmtBlockWithScope(exprs, span) => {
863	                Expr::StmtBlock(exprs.clone(), *span).returned_type(cte, *span)
864	            }
865	            _ => None,
866	        }
867	    }
868	
869	    fn get_span(&self) -> Span {
870	        match self {
871	            Expr::Add(_, _, span)
872	            | Expr::Sub(_, _, span)
873	            | Expr::Mult(_, _, span)
874	            | Expr::Div(_, _, span)
875	            | Expr::Power(_, _, span)
876	            | Expr::Mod(_, _, span)
877	            | Expr::BangEqual(_, _, span)
878	            | Expr::EqualEqual(_, _, span)
879	            | Expr::GreaterEqual(_, _, span)
880	            | Expr::LessEqual(_, _, span)
881	            | Expr::Less(_, _, span)
882	            | Expr::Greater(_, _, span)
883	            | Expr::Return(_, span) => *span,
884	            _ => Span::empty(),
885	        }
886	    }
887	}
