37	impl fmt::Display for Value {
38	    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
39	        if self.value_type.has_tag("func") {
40	            if self.native.is_some() {
41	                panic!("Expected body for function");
42	            } else {
43	                write!(f, "{}", self.body.clone().unwrap().return_type)
44	            }
45	        } else if self.value_type.has_tag("vec") || self.value_type.has_tag("arr") {
46	            write!(f, "[")?;
47	            for v in self.value_vec.clone().unwrap() {
48	                write!(f, "{}, ", v)?;
49	            }
